def count_beautiful_pairs(nums):
    def first_digit(num):
        while num >= 10:
            num //= 10
        return num

    def last_digit(num):
        return num % 10

    def gcd(a, b):
        while b:
            a, b = b, a % b
        return a

    count = 0
    n = len(nums)
    for i in range(n):
        for j in range(i + 1, n):
            if gcd(first_digit(nums[i]), last_digit(nums[j])) == 1:
                count += 1
    return count
